//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagefwdiag_testimport("testing""github.com/hashicorp/terraform-plugin-framework/diag""github.com/hashicorp/terraform-provider-aws/internal/errs/fwdiag")funcTestDiagnosticsError(t*testing.T){t.Parallel()testCases:=[]struct{testNamestringdiagsdiag.DiagnosticswantErrbool}{{testName:"nilDiagnostics",},{testName:"singlewarningDiagnostics",diags:diag.Diagnostics{diag.NewWarningDiagnostic("summary","detail")},},{testName:"singleerrorDiagnostics",diags:diag.Diagnostics{diag.NewErrorDiagnostic("summary","detail")},wantErr:true,},{testName:"mixedwarninganderrorDiagnostics",diags:diag.Diagnostics{diag.NewWarningDiagnostic("summary1","detail1"),diag.NewErrorDiagnostic("summary2","detail2"),},wantErr:true,},{testName:"multipleerrorDiagnostics",diags:diag.Diagnostics{diag.NewErrorDiagnostic("summary1","detail1"),diag.NewErrorDiagnostic("summary2","detail2"),},wantErr:true,},{testName:"multiplewarningDiagnostics",diags:diag.Diagnostics{diag.NewWarningDiagnostic("summary1","detail1"),diag.NewWarningDiagnostic("summary2","detail2"),},},}for_,testCase:=rangetestCases{testCase:=testCaset.Run(testCase.testName,func(t*testing.T){t.Parallel()err:=fwdiag.DiagnosticsError(testCase.diags)gotErr:=err!=nilifgotErr!=testCase.wantErr{t.Errorf("gotErr=%v,wantErr=%v",gotErr,testCase.wantErr)}})}}